import{_ as e,a as o}from"./chunks/查询额度成功.wz9SQqrH.js";import{_ as t,o as d,c as n,a2 as i}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Adicionar canal pCloud","description":"","frontmatter":{},"headers":[],"relativePath":"pt-BR/upload/pcloud.md","filePath":"pt-BR/upload/pcloud.md","lastUpdated":1781962217000}'),s={name:"pt-BR/upload/pcloud.md"};function r(l,a,p,c,u,h){return d(),n("div",null,[...a[0]||(a[0]=[i('<h1 id="adicionar-canal-pcloud" tabindex="-1">Adicionar canal pCloud <a class="header-anchor" href="#adicionar-canal-pcloud" aria-label="Permalink to &quot;Adicionar canal pCloud&quot;">​</a></h1><p>O canal pCloud usa sua conta pCloud como destino de armazenamento.</p><h2 id="quando-usar" tabindex="-1">Quando usar <a class="header-anchor" href="#quando-usar" aria-label="Permalink to &quot;Quando usar&quot;">​</a></h2><ul><li>Você já tem conta pCloud.</li><li>Quer salvar imagens ou arquivos no espaço pCloud.</li><li>Pode usar e-mail e senha como credenciais do canal.</li></ul><h2 id="o-que-preparar" tabindex="-1">O que preparar <a class="header-anchor" href="#o-que-preparar" aria-label="Permalink to &quot;O que preparar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Item</th><th>Uso</th></tr></thead><tbody><tr><td>E-mail pCloud</td><td>Login na API do pCloud</td></tr><tr><td>Senha pCloud</td><td>Login na API do pCloud</td></tr><tr><td>Host</td><td>Normalmente <code>api.pcloud.com</code>; para Europa <code>eapi.pcloud.com</code></td></tr><tr><td>Diretório</td><td>Opcional, normalmente <code>imgbed</code></td></tr></tbody></table><h2 id="onde-adicionar" tabindex="-1">Onde adicionar <a class="header-anchor" href="#onde-adicionar" aria-label="Permalink to &quot;Onde adicionar&quot;">​</a></h2><ol><li>Abra Configurações do sistema.</li><li>Entre em Configurações de upload.</li><li>Clique em <code>Adicionar canal</code>.</li><li>Escolha <code>pCloud</code>.</li></ol><h2 id="campos" tabindex="-1">Campos <a class="header-anchor" href="#campos" aria-label="Permalink to &quot;Campos&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Campo</th><th>Valor</th></tr></thead><tbody><tr><td>Nome do canal</td><td>Por exemplo <code>pCloud Main</code></td></tr><tr><td>E-mail</td><td>E-mail de login do pCloud</td></tr><tr><td>Senha</td><td>Senha do pCloud</td></tr><tr><td>Host</td><td>Normalmente <code>api.pcloud.com</code></td></tr><tr><td>Diretório</td><td>Opcional, padrão <code>imgbed</code></td></tr></tbody></table><p>O Host depende da região da conta.</p><table tabindex="0"><thead><tr><th>Região</th><th>Host</th></tr></thead><tbody><tr><td>Padrão / Estados Unidos</td><td><code>api.pcloud.com</code></td></tr><tr><td>Europa</td><td><code>eapi.pcloud.com</code></td></tr></tbody></table><p><img src="'+e+'" alt="Configuração pCloud" loading="lazy"></p><h2 id="verificacao" tabindex="-1">Verificação <a class="header-anchor" href="#verificacao" aria-label="Permalink to &quot;Verificação&quot;">​</a></h2><p>Depois de salvar, o cartão do canal deve aparecer. Se a consulta de capacidade funcionar, a conexão está correta.</p><p><img src="'+o+`" alt="Consulta de capacidade" loading="lazy"></p><p>Depois envie uma imagem de teste e confira se ela aparece no diretório do pCloud.</p><h2 id="perguntas-comuns" tabindex="-1">Perguntas comuns <a class="header-anchor" href="#perguntas-comuns" aria-label="Permalink to &quot;Perguntas comuns&quot;">​</a></h2><h3 id="por-que-nao-oauth2" tabindex="-1">Por que não OAuth2? <a class="header-anchor" href="#por-que-nao-oauth2" aria-label="Permalink to &quot;Por que não OAuth2?&quot;">​</a></h3><p>O OAuth2 do pCloud não fica disponível como fluxo aberto por padrão e exige ativação oficial. Além disso, o fluxo atual não combina bem com as URLs temporárias de upload que o ImgBed precisa, então o canal usa e-mail e senha.</p><h3 id="qual-host-usar" tabindex="-1">Qual Host usar? <a class="header-anchor" href="#qual-host-usar" aria-label="Permalink to &quot;Qual Host usar?&quot;">​</a></h3><p>Normalmente:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>api.pcloud.com</span></span></code></pre></div><p>Para contas europeias:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>eapi.pcloud.com</span></span></code></pre></div><h2 id="fluxo-rapido" tabindex="-1">Fluxo rápido <a class="header-anchor" href="#fluxo-rapido" aria-label="Permalink to &quot;Fluxo rápido&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Preparar e-mail e senha do pCloud</span></span>
<span class="line"><span>-&gt; Abrir Configurações de upload</span></span>
<span class="line"><span>-&gt; Adicionar canal</span></span>
<span class="line"><span>-&gt; Escolher pCloud</span></span>
<span class="line"><span>-&gt; Preencher nome / e-mail / senha</span></span>
<span class="line"><span>-&gt; Conferir Host</span></span>
<span class="line"><span>-&gt; Salvar</span></span>
<span class="line"><span>-&gt; Consultar capacidade</span></span>
<span class="line"><span>-&gt; Enviar imagem de teste</span></span></code></pre></div>`,27)])])}const C=t(s,[["render",r]]);export{g as __pageData,C as default};
